import sys, types, threading, time

from assay_engine.persistence import checkpoint as cp

def build_fake(state, widen=False):
    class FakeConn:
        def execute(self, sql, params=None):
            if "pg_advisory_lock" in sql:
                state["lock_on"].append(id(self))
    class FakePool:
        check_connection = staticmethod(lambda *a, **k: None)
        def __init__(self, conn_str, **kw):
            self._conn = FakeConn()
            state["pools"].append(self)
        def connection(self):
            conn = self._conn
            class _Ctx:
                def __enter__(self_): return conn
                def __exit__(self_, *a): return False
            return _Ctx()
        def close(self): pass
    class FakeSaver:
        def __init__(self, arg): self.arg = arg
        def setup(self):
            if widen:
                time.sleep(0.002)   # widen the check->set window
            state["setup_on"].append(id(self.arg))
    def _mod(name, **attrs):
        m = types.ModuleType(name)
        for k, v in attrs.items(): setattr(m, k, v)
        sys.modules[name] = m
        return m
    _mod("langgraph"); _mod("langgraph.checkpoint")
    _mod("langgraph.checkpoint.postgres", PostgresSaver=FakeSaver)
    _mod("langgraph.checkpoint.memory", MemorySaver=type("MemorySaver", (), {}))
    _mod("psycopg"); _mod("psycopg.rows", dict_row=object())
    _mod("psycopg_pool", ConnectionPool=FakePool)

def run(remove_lock):
    state = {"setup_on": [], "lock_on": [], "pools": []}
    build_fake(state, widen=True)
    cp._INITIALIZED_CONN_STRS = set()
    cp._OPEN_POOLS = []
    cp._atexit_registered = True   # skip atexit noise
    import os; os.environ["ASSAY_POSTGRES_URL"] = "postgresql://localhost:5432/assay"

    if remove_lock:
        # Monkeypatch _init_lock to a no-op so the bootstrap block is NOT serialized.
        class _NoLock:
            def __enter__(self): return self
            def __exit__(self, *a): return False
        cp._init_lock = _NoLock()
    else:
        cp._init_lock = threading.Lock()

    n = 8
    barrier = threading.Barrier(n)
    errors = []
    def worker():
        barrier.wait()
        try:
            cp.get_checkpointer()
        except Exception as e:
            errors.append(e)
    threads = [threading.Thread(target=worker) for _ in range(n)]
    for t in threads: t.start()
    for t in threads: t.join()
    return len(state["setup_on"]), errors

for label, remove in [("WITH lock", False), ("WITHOUT lock (no-op)", True)]:
    times = [run(remove)[0] for _ in range(5)]
    print(f"{label}: setup() call counts across 5 runs = {times}")
